; マップを開いた時に必ず実行されるスクリプト
[initial]

sky = o.水竜の神殿Ｂ４.underWater ? "black" : "deepwater";

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] true

@wait time=500
[texton]
[？？？]「I am the guardian of the temple. You are not allowed to proceed beyond this point.」[k]
Something attacked![k]
[textoff]
@monster pos=3 name=ストーンゴーレム
@callbattle bgm=boss gameover=true
@delevent

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@wait time=500
[texton]
[リーダー f=12]「...!」[k]
Suddenly, I felt a terrifying killing intent from behind that made my whole body tremble![k]
[？？？]「Who disturbs my slumber?」[k]
An eerie voice echos around me! Something is here![k]
[textoff]
@wait time=500
@walk move=w cond='game.party.curX > 9'
@walk move=e cond='game.party.curX < 9'
@walk turn=n cond='WAY == "s"'
@walk move=n
@walk move=n
@wait time=500
@se f=bashan1
@flash on=200
@wait time=1000
@fgf c=dragon_blue left=450 top=-90
@flash off=500
@wait time=1000
[texton]
Behind me stood a huge blue dragon![r]
The dragon suddenly attacked![k]
[textoff]
@clf
@monster pos=3 name=アクアドラゴン
@callbattle bgm=dragon gameover=true escape=false
@delevent

[eventoff]
